	}

	_, err = collection.InsertOne(ctx, doc1)
	if err != nil {
		log.Fatal(err)
	}

	// Create and insert the second document - explicit mapping
	doc2 := bson.D{
		{"mappingType", "explicit"},
		{"input", bson.A{"boat"}},
		{"synonyms", bson.A{"boat", "vessel", "sail"}},
	}

	_, err = collection.InsertOne(ctx, doc2)
	if err != nil {
		log.Fatal(err)
