If you are running a free tier cluster or a Flex cluster,
follow the steps in the Transportation Synonyms tab to create the collection
for a single synonym mapping definition in your index. If you have a
`M10` or higher cluster and wish to create multiple synonym
mappings in your index, follow the steps in the Multiple Synonyms tab to create
both the Transportation Synonyms and Attire Synonyms collections.

Transport Synonyms

Create and populate the `transport_synonyms` collection:

```cpp
#include <iostream>
#include <bsoncxx/builder/stream/document.hpp>
#include <bsoncxx/builder/stream/array.hpp>
#include <bsoncxx/json.hpp>
#include <mongocxx/client.hpp>
#include <mongocxx/instance.hpp>
#include <mongocxx/uri.hpp>
#include <mongocxx/exception/exception.hpp>

using bsoncxx::builder::stream::document;
using bsoncxx::builder::stream::array;
using bsoncxx::builder::stream::open_document;
using bsoncxx::builder::stream::close_document;
using bsoncxx::builder::stream::open_array;
using bsoncxx::builder::stream::close_array;
using bsoncxx::builder::stream::finalize;

int main() {
    try {
        // Initialize the MongoDB C++ driver
        mongocxx::instance instance{};

        // Create a MongoDB client
        const auto uri = mongocxx::uri{"<connection-string>"};
        mongocxx::client client{uri};

        // Get the sample_mflix database
        auto db = client["sample_mflix"];

        // Create the transport_synonyms collection
        try {
            db.create_collection("transport_synonyms");
        } catch (const mongocxx::exception& e) {
            // Collection may already exist, which is fine
            std::cerr << "Note: " << e.what() << std::endl;
        }

        auto collection = db["transport_synonyms"];

        // Create and insert the first document - equivalent mapping
        auto doc1 = document{}
            << "mappingType" << "equivalent"
            << "synonyms" << open_array
                << "car" << "vehicle" << "automobile"
            << close_array
            << finalize;

        collection.insert_one(doc1.view());

        // Create and insert the second document - explicit mapping
        auto doc2 = document{}
            << "mappingType" << "explicit"
            << "input" << open_array
                << "boat"
            << close_array
            << "synonyms" << open_array
                << "boat" << "vessel" << "sail"
            << close_array
            << finalize;

        collection.insert_one(doc2.view());

        std::cout << "Synonyms collections successfully created and populated." << std::endl;

    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return EXIT_FAILURE;
    }

    return EXIT_SUCCESS;
}

```

Multiple Synonyms

Create and populate both the `transport_synonyms` and `attire_synonyms` collections:

```cpp
#include <iostream>
#include <bsoncxx/builder/stream/document.hpp>
#include <bsoncxx/builder/stream/array.hpp>
#include <bsoncxx/json.hpp>
#include <mongocxx/client.hpp>
#include <mongocxx/instance.hpp>
#include <mongocxx/uri.hpp>
#include <mongocxx/exception/exception.hpp>

using bsoncxx::builder::stream::document;
using bsoncxx::builder::stream::array;
using bsoncxx::builder::stream::open_document;
using bsoncxx::builder::stream::close_document;
using bsoncxx::builder::stream::open_array;
using bsoncxx::builder::stream::close_array;
using bsoncxx::builder::stream::finalize;

int main() {
    try {
        // Initialize the MongoDB C++ driver
        mongocxx::instance instance{};

        // Create a MongoDB client
        const auto uri = mongocxx::uri{"<connection-string>"};
        mongocxx::client client{uri};

        // Get the sample_mflix database
        auto db = client["sample_mflix"];

        // Create the transport_synonyms collection
        try {
            db.create_collection("transport_synonyms");
        } catch (const mongocxx::exception& e) {
            // Collection may already exist, which is fine
            std::cerr << "Note: " << e.what() << std::endl;
        }

        auto transport_collection = db["transport_synonyms"];

        // Create and insert the first transport document - equivalent mapping
        auto doc1 = document{}
            << "mappingType" << "equivalent"
            << "synonyms" << open_array
                << "car" << "vehicle" << "automobile"
            << close_array
            << finalize;

        transport_collection.insert_one(doc1.view());

        // Create and insert the second transport document - explicit mapping
        auto doc2 = document{}
            << "mappingType" << "explicit"
            << "input" << open_array
                << "boat"
            << close_array
            << "synonyms" << open_array
                << "boat" << "vessel" << "sail"
            << close_array
            << finalize;

        transport_collection.insert_one(doc2.view());

        // Create the attire_synonyms collection
        try {
            db.create_collection("attire_synonyms");
        } catch (const mongocxx::exception& e) {
            // Collection may already exist, which is fine
            std::cerr << "Note: " << e.what() << std::endl;
        }

        auto attire_collection = db["attire_synonyms"];

        // Create and insert the first attire document - equivalent mapping
        auto doc3 = document{}
            << "mappingType" << "equivalent"
            << "synonyms" << open_array
                << "dress" << "apparel" << "attire"
            << close_array
            << finalize;

        attire_collection.insert_one(doc3.view());

        // Create and insert the second attire document - explicit mapping
        auto doc4 = document{}
            << "mappingType" << "explicit"
            << "input" << open_array
                << "hat"
            << close_array
            << "synonyms" << open_array
                << "hat" << "fedora" << "headgear"
            << close_array
            << finalize;

        attire_collection.insert_one(doc4.view());

        std::cout << "Synonyms collections successfully created and populated." << std::endl;

    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return EXIT_FAILURE;
    }

    return EXIT_SUCCESS;
}

```

Replace `<connection-string>` with the connection string for your
Atlas cluster or local Atlas deployment.

Atlas Cluster

Your connection string should use the following format:

```
mongodb+srv://<db_username>:<db_password>@<clusterName>.<hostname>.mongodb.net
```

To learn more, see [Driver](connect-via-driver).

Local or Self-Managed

Your connection string should use the
following format:

```
mongodb://localhost:<port-number>/?directConnection=true
```

To learn more, see [Connection Strings](manual/reference/connection-string).

