  .then((client) => {
    const coll = client.db("sample_mflix").collection("movies");
    return coll
      .aggregate(agg)
      .toArray()
      .then((results) => {
        console.log(results);
        client.close();
        process.exit(0);
      });
  })
  .catch((err) => {
    console.error("Error:", err);
    process.exit(1);
